srcDoc.js:
let chart;
function renderChart() {
  const gmina = Number(appsmith.model.gmina || 0);
  const bazowa = Number(appsmith.model.bazowa || 0);
  const rok = appsmith.model.rok || "";
  const colors = [gmina > bazowa ? "#fca5a5" : gmina < bazowa ? "#bbf7d0" : "#6B778E", "#6B778E"];
  const el = document.getElementById("chart");
  if (!chart) {
    chart = echarts.init(el);
  }
  chart.setOption({
    title: {
      text: "Stosunek wskaźnika do wartości bazowej",
      subtext: "Rok: " + rok,
      left: "center",
      top: 15,
      textStyle: {
        fontSize: 18,
        fontWeight: "bold",
        color: "#64748b"
      },
      subtextStyle: {
        fontSize: 12,
        fontWeight: "normal",
        color: "#374151"
      }
    },
    tooltip: {
      trigger: "axis",
      axisPointer: {
        type: "shadow"
      }
    },
    grid: {
      left: 70,
      right: 40,
      top: 110,
      bottom: 70
    },
    xAxis: {
      type: "category",
      data: [appsmith.model.gminaLabel || "Gmina", "Wartość bazowa"],
      axisTick: {
        alignWithLabel: true
      },
      axisLabel: {
        color: "#6B7280",
        fontSize: 13
      },
      axisLine: {
        lineStyle: {
          color: "#9CA3AF"
        }
      }
    },
    yAxis: {
      type: "value",
      name: "Przychód",
      nameLocation: "middle",
      nameGap: 50,
      axisLabel: {
        color: "#6B7280"
      },
      splitLine: {
        lineStyle: {
          color: "#E5E7EB"
        }
      }
    },
    series: [{
      name: rok,
      type: "bar",
      barWidth: "55%",
      data: [{
        value: gmina,
        itemStyle: {
          color: colors[0]
        }
      }, {
        value: bazowa,
        itemStyle: {
          color: colors[1]
        }
      }],
      label: {
        show: true,
        position: "top",
        fontSize: 13,
        fontWeight: "normal",
        color: "#374151",
        formatter: function (params) {
          return params.value.toLocaleString("pl-PL", {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2
          });
        }
      }
    }]
  });
  chart.resize();
}
appsmith.onReady(() => {
  renderChart();
  appsmith.onModelChange(() => {
    renderChart();
  });
  window.addEventListener("resize", () => {
    if (chart) {
      chart.resize();
    }
  });
});

